def singleNumber(nums):
    result = 0
    for i in range(32):
        bit_count = 0
        for num in nums:
            bit_count += (num >> i) & 1
        if bit_count % 3 != 0:
            result |= 1 << i
    if result >= (1 << 31):
        result -= 1 << 32
    return result

